class RangeModule {
public:
    RangeModule() {

    }

    void addRange(int left, int right) {
        auto it = intervals.lower_bound({left, 0});
        vector<pair<int, int>> temp;
        bool flag = false;
        for (; it != intervals.end() && it->first < right; ++it) {
            if (it->first >= left) {
                left = min(left, it->first);
                right = max(right, it->second);
                flag = true;
            } else {
                if (!flag) temp.push_back({left, right});
                temp.push_back({it->first, it->second});
            }
        }
        if (!flag) temp.push_back({left, right});
        intervals = temp;
    }

    bool queryRange(int left, int right) {
        auto it = intervals.lower_bound({left, 0});
        if (it == intervals.begin() || prev(it)->second < left) return false;
        return prev(it)->second >= right;
    }

    void removeRange(int left, int right) {
        auto it = intervals.lower_bound({left, 0});
        vector<pair<int, int>> temp;
        bool flag = false;
        for (; it != intervals.end() && it->first < right; ++it) {
            if (it->first >= left && it->second <= right) {
                flag = true;
                continue;
            }
            if (it->first < left) temp.push_back({it->first, min(it->second, left)});
            if (it->second > right) temp.push_back({right, it->second});
            flag = true;
        }
        if (!flag) temp = intervals;
        intervals = temp;
    }
private:
    set<pair<int, int>> intervals;
};
